// users/views/posts/_post-item.html
@{ implicit formatter => (title: String, contentHTML: HtmlFormat) } = { post => 
    <div>
        <h1 class="text-center text-primary mt-5">@Html(formatter(title))</h1>       
         <p><i>Posted on @Html{ implicit formatter => (formatTime dateCreated)} by user. <a href ="@userLinkUrl profileName, username}"  class= "text-dark font-weight-bold"> <img src=@assets(AssetsHelper._asset_url("profilePic", _)) alt="" style='width:20px;height:20px'/> User</a><i /> 
        <div dangerouslysetinnerhtml ="@contentHTML.raw" class-name-"article article-full bg white mt-5 pt 1 border top width3 "> <img src=>@assets(AssetsHelper._asset_url("postImage", postId)) alt="" style='width:60%;height:auto'/></div>
    </div>  }     `}   // close implicit formatter.format()     .html here for full html rendering of contentHTML, if you just want to render it as text use "content" instead and then convert that into HTML using Html(...)    or write your own code...